using UnityEngine;

public class BallBouncer : MonoBehaviour
{
    [Tooltip("Coefficient of restitution (0 = no bounce, 1 = perfect bounce).")]
    public float bounciness = 0.8f;
    [Tooltip("Minimum Y-component of collision normal to be considered \"floor\".")]
    public float floorNormalThreshold = 0.7f;
    [Tooltip("Minimum downward impact velocity along the normal to trigger a bounce.")]
    public float minImpactVelocityForBounce = 0.1f;

    private Rigidbody rb;

    void Start()
    {
        rb = GetComponent<Rigidbody>();
        if (rb == null)
        {
            Debug.LogError("BallBouncer requires a Rigidbody component on the GameObject. Disabling script.");
            enabled = false;
        }
    }

    void OnCollisionEnter(Collision collision)
    {
        if (rb == null || !enabled) return;

        // Get the average normal of the collision contacts.
        Vector3 collisionNormal = Vector3.zero;
        if (collision.contacts.Length > 0)
        {
            foreach (ContactPoint contact in collision.contacts)
            {
                collisionNormal += contact.normal;
            }
            collisionNormal.Normalize();
        }
        else
        {
            // If no contacts, can't determine normal, so exit.
            return;
        }

        // Check if the collision surface is predominantly a "floor" (normal points upwards)
        // and if the ball is moving downwards with sufficient velocity.
        if (collisionNormal.y > floorNormalThreshold)
        {
            // Calculate the velocity component of the ball along the collision normal.
            // This represents the speed at which the ball is approaching (or receding from) the surface.
            float relativeVelocityAlongNormal = Vector3.Dot(rb.velocity, collisionNormal);

            // Only apply bounce if the ball is moving towards the surface (negative relativeVelocityAlongNormal)
            // and the impact is significant enough.
            if (relativeVelocityAlongNormal < -minImpactVelocityForBounce)
            {
                // Calculate the desired change in velocity along the normal.
                // The new velocity along the normal should be the negative of the old, scaled by bounciness.
                // Δv = (v_final - v_initial) = (-v_initial * bounciness) - v_initial
                float desiredChangeInVelocityAlongNormal = (-relativeVelocityAlongNormal * bounciness) - relativeVelocityAlongNormal;

                // Apply the impulse in the direction of the collision normal.
                // This makes the ball bounce off the surface at the appropriate angle.
                rb.AddForce(collisionNormal * desiredChangeInVelocityAlongNormal, ForceMode.Impulse);
            }
        }
    }
}

using UnityEngine;

public class SlowFallUnderwater : MonoBehaviour
{
    [Tooltip("The drag coefficient applied when underwater.")]
    public float underwaterDrag = 5f;
    [Tooltip("The angular drag coefficient applied when underwater.")]
    public float underwaterAngularDrag = 5f;
    [Tooltip("The upward force applied to simulate buoyancy.")]
    public float buoyancyForceMagnitude = 1f;

    private Rigidbody rb;

    void Start()
    {
        rb = GetComponent<Rigidbody>();
        if (rb == null)
        {
            Debug.LogWarning("Rigidbody not found on " + gameObject.name + ". SlowFallUnderwater script requires a Rigidbody to function.");
            enabled = false; // Disable the script if no Rigidbody
            return;
        }

        // Apply initial drag settings for underwater effect
        rb.drag = underwaterDrag;
        rb.angularDrag = underwaterAngularDrag;
    }

    void FixedUpdate()
    {
        // Apply a constant upward force to simulate buoyancy
        if (rb != null)
        {
            rb.AddForce(Vector3.up * buoyancyForceMagnitude, ForceMode.Acceleration);
        }
    }
}

using UnityEngine;

public class DoorProximityOpener : MonoBehaviour
{
    public GameObject player; // Assign the Player GameObject in the Inspector
    public float activationDistance = 1f; // The distance to activate the door
    public float openAmount = 3f; // How much the door moves upwards when open
    public float openSpeed = 1f; // Speed of opening/closing

    private Vector3 initialPosition;
    private Vector3 targetOpenPosition;

    void Start()
    {
        initialPosition = transform.position;
        targetOpenPosition = initialPosition + Vector3.up * openAmount; // Moves the door upwards

        // If player is not assigned, try to find it by name based on the scene description
        if (player == null)
        {
            player = GameObject.Find("Player");
            if (player == null)
            {
                Debug.LogError("Player GameObject not found. Please assign it in the inspector or ensure it is named 'Player'.");
            }
        }
    }

    void Update()
    {
        if (player == null) return;

        float distanceToPlayer = Vector3.Distance(transform.position, player.transform.position);

        if (distanceToPlayer < activationDistance)
        {
            // Move door towards the open position
            transform.position = Vector3.MoveTowards(transform.position, targetOpenPosition, openSpeed * Time.deltaTime);
        }
        else
        {
            // Move door back towards the initial (closed) position
            transform.position = Vector3.MoveTowards(transform.position, initialPosition, openSpeed * Time.deltaTime);
        }
    }
}

