using UnityEngine;
using UnityEngine.XR.Interaction.Toolkit;

[RequireComponent(typeof(Rigidbody))]
[RequireComponent(typeof(XRGrabInteractable))]
public class CustomGrabMovement : MonoBehaviour
{
    private XRGrabInteractable _grabInteractable;
    private IXRSelectInteractor _currentInteractor;
    private bool _isGrabbed = false;

    void Awake()
    {
        _grabInteractable = GetComponent<XRGrabInteractable>();
        if (_grabInteractable == null)
        {
            Debug.LogError("XRGrabInteractable not found on this GameObject.");
            return;
        }

        // Disable default tracking so our script can control movement directly
        _grabInteractable.trackPosition = false;
        _grabInteractable.trackRotation = false;

        _grabInteractable.firstSelectEntered.AddListener(OnGrab);
        _grabInteractable.lastSelectExited.AddListener(OnRelease);
    }

    void OnDestroy()
    {
        if (_grabInteractable != null)
        {
            _grabInteractable.firstSelectEntered.RemoveListener(OnGrab);
            _grabInteractable.lastSelectExited.RemoveListener(OnRelease);
        }
    }

    private void OnGrab(SelectEnterEventArgs args)
    {
        _currentInteractor = args.interactorObject;
        _isGrabbed = true;

        // Make the Rigidbody kinematic while grabbed for direct transform control
        Rigidbody rb = GetComponent<Rigidbody>();
        if (rb != null)
        {
            rb.isKinematic = true;
        }
    }

    private void OnRelease(SelectExitEventArgs args)
    {
        _currentInteractor = null;
        _isGrabbed = false;

        // Re-enable physics simulation upon release
        Rigidbody rb = GetComponent<Rigidbody>();
        if (rb != null)
        {
            rb.isKinematic = false;
        }
    }

    void FixedUpdate()
    {
        if (_isGrabbed && _currentInteractor != null)
        {
            // Directly set position and rotation to follow the interactor
            transform.position = _currentInteractor.transform.position;
            transform.rotation = _currentInteractor.transform.rotation;
        }
    }
}

using UnityEngine;

public class GazeScale : MonoBehaviour
{
    private Vector3 originalScale;
    public float scaleMultiplier = 1.2f;
    private Camera mainCamera;

    void Start()
    {
        originalScale = transform.localScale;
        mainCamera = Camera.main;
        if (mainCamera == null)
        {
            Debug.LogError("Main Camera not found. Please ensure your camera is tagged 'MainCamera'.");
            enabled = false; // Disable the script if no main camera
        }
    }

    void Update()
    {
        if (mainCamera == null) return;

        Ray ray = new Ray(mainCamera.transform.position, mainCamera.transform.forward);
        RaycastHit hit;

        if (Physics.Raycast(ray, out hit))
        {
            if (hit.collider.gameObject == gameObject)
            {
                // Object is being looked at, make it bigger
                transform.localScale = originalScale * scaleMultiplier;
            }
            else
            {
                // Another object is being looked at, or nothing is hit. Return to original scale.
                transform.localScale = originalScale;
            }
        }
        else
        {
            // Nothing is being looked at. Return to original scale.
            transform.localScale = originalScale;
        }
    }
}
